import React, { useState, useMemo } from 'react';

const theme = {
  bg: '#0a0a0a',
  surface: '#111111',
  surfaceAlt: '#1a1a1a',
  border: '#2a2a2a',
  text: '#fafafa',
  textSecondary: '#a1a1aa',
  textMuted: '#52525b',
  primary: '#8b5cf6',
  font: "'JetBrains Mono', monospace",
};

const COLORS = ['#f43f5e', '#4ade80', '#fbbf24', '#60a5fa'];
const COLOR_NAMES = ['Red', 'Green', 'Gold', 'Blue'];
const NUM_COLORS = 4;

const presets = [
  { label: 'All Same', apples: [0,0,0,0,0,0,0,0] },
  { label: 'Half & Half', apples: [0,0,0,0,1,1,1,1] },
  { label: 'One Dominant', apples: [0,0,0,0,0,1,2,3] },
  { label: 'Uniform Mix', apples: [0,1,2,3,0,1,2,3] },
];

export default function App() {
  const [apples, setApples] = useState([0, 0, 0, 0, 0, 0, 0, 0]);
  const [clickPulse, setClickPulse] = useState(-1);

  const toggleApple = (idx) => {
    setApples(prev => {
      const next = [...prev];
      next[idx] = (next[idx] + 1) % NUM_COLORS;
      return next;
    });
    setClickPulse(idx);
    setTimeout(() => setClickPulse(-1), 200);
  };

  const { gini, terms, activeTerms, sumPSq } = useMemo(() => {
    const total = apples.length;
    const counts = [0, 0, 0, 0];
    apples.forEach(a => counts[a]++);
    const t = counts.map((count, i) => {
      const p = count / total;
      return { color: i, count, p, pSq: p * p };
    });
    const sPSq = t.reduce((sum, term) => sum + term.pSq, 0);
    const g = 1 - sPSq;
    return {
      gini: Math.round(g * 10000) / 10000,
      terms: t,
      activeTerms: t.filter(x => x.count > 0),
      sumPSq: Math.round(sPSq * 10000) / 10000,
    };
  }, [apples]);

  const giniColor = gini === 0 ? theme.textMuted : gini > 0.6 ? '#f43f5e' : gini > 0.3 ? '#fbbf24' : '#fb923c';
  const giniPct = Math.min((gini / 0.75) * 100, 100);

  const getInsight = () => {
    const distinct = activeTerms.length;
    if (gini === 0) return 'Zero disorder! All apples share the same color. Gini = 0 when only one class exists.';
    if (gini >= 0.74) return 'Maximum disorder for 4 colors! Each has equal share (1/4), so Gini = 1 - 4*(0.25)^2 = 0.75.';
    if (distinct === 2 && Math.abs(gini - 0.5) < 0.001) return 'Two equally sized groups, like a fair coin. Gini = 1 - 2*(0.5)^2 = 0.5.';
    if (distinct === 2) return distinct + ' colors present. The more balanced they are, the higher the disorder.';
    if (gini > 0.5) return distinct + ' colors present with moderate balance. More even splits push disorder higher.';
    return distinct + ' colors present but one dominates. Dominant colors suppress disorder.';
  };

  const svgW = 500;
  const svgH = 90;
  const appleR = 26;
  const gap = svgW / 8;

  return (
    <div style={{
      maxWidth: 600, margin: '0 auto', padding: '20px 16px',
      fontFamily: theme.font, background: theme.bg, color: theme.text,
      minHeight: '100vh', boxSizing: 'border-box',
    }}>
      {/* Title */}
      <div style={{ marginBottom: 16 }}>
        <h1 style={{ fontSize: 18, fontWeight: 700, margin: 0, marginBottom: 4 }}>
          Apple Basket Disorder
        </h1>
        <p style={{ fontSize: 12, color: theme.textMuted, margin: 0 }}>
          Click each apple to cycle its color. Watch Gini impurity respond.
        </p>
      </div>

      {/* Presets */}
      <div style={{ display: 'flex', gap: 6, marginBottom: 14, flexWrap: 'wrap' }}>
        {presets.map((p, i) => {
          const isActive = JSON.stringify(apples) === JSON.stringify(p.apples);
          return (
            <button
              key={i}
              onClick={() => setApples([...p.apples])}
              style={{
                padding: '5px 11px', borderRadius: 6,
                border: isActive ? '1px solid ' + theme.primary : '1px solid ' + theme.border,
                background: isActive ? theme.primary + '22' : theme.surfaceAlt,
                color: isActive ? theme.primary : theme.textSecondary,
                fontSize: 11, cursor: 'pointer', fontFamily: theme.font,
                transition: 'all 0.2s',
              }}
            >
              {p.label}
            </button>
          );
        })}
      </div>

      {/* Apple Basket - MAIN INTERACTION */}
      <div style={{
        background: theme.surface, borderRadius: 12, padding: '18px 12px 14px',
        marginBottom: 14, border: '1px solid ' + theme.border,
        textAlign: 'center',
      }}>
        <div style={{ fontSize: 10, color: theme.textMuted, marginBottom: 10, textTransform: 'uppercase', letterSpacing: 1 }}>
          Click to change color
        </div>
        <svg
          width="100%"
          viewBox={'0 0 ' + svgW + ' ' + svgH}
          style={{ display: 'block', maxWidth: svgW }}
        >
          {apples.map((color, i) => {
            const cx = gap / 2 + i * gap;
            const cy = svgH / 2;
            const isPulsing = clickPulse === i;
            const r = isPulsing ? appleR + 5 : appleR;
            return (
              <g
                key={i}
                onClick={() => toggleApple(i)}
                style={{ cursor: 'pointer' }}
              >
                {/* Shadow */}
                <ellipse cx={cx} cy={cy + appleR + 6} rx={appleR * 0.7} ry={4} fill="rgba(0,0,0,0.25)" />
                {/* Glow on pulse */}
                {isPulsing && (
                  <circle cx={cx} cy={cy} r={appleR + 10} fill={COLORS[color]} opacity={0.15} />
                )}
                {/* Apple body */}
                <circle cx={cx} cy={cy} r={r} fill={COLORS[color]} opacity={isPulsing ? 1 : 0.85}
                  style={{ transition: 'r 0.15s ease, opacity 0.15s ease' }} />
                {/* Highlight */}
                <circle cx={cx - 8} cy={cy - 8} r={7} fill="rgba(255,255,255,0.18)" />
                {/* Stem */}
                <line x1={cx} y1={cy - appleR + 5} x2={cx + 3} y2={cy - appleR - 5}
                  stroke="#8B7355" strokeWidth={2.5} strokeLinecap="round" />
                {/* Leaf */}
                <ellipse cx={cx + 7} cy={cy - appleR - 3} rx={5} ry={3}
                  fill="#4ade80" opacity={0.7}
                  transform={'rotate(30 ' + (cx + 7) + ' ' + (cy - appleR - 3) + ')'} />
                {/* Color number */}
                <text x={cx} y={cy + 1} textAnchor="middle" dominantBaseline="middle"
                  fontSize={13} fontWeight={700} fill="rgba(0,0,0,0.4)"
                  style={{ pointerEvents: 'none' }}>
                  {color}
                </text>
              </g>
            );
          })}
        </svg>
      </div>

      {/* Gini Display */}
      <div style={{
        background: theme.surface, borderRadius: 12, padding: 16,
        marginBottom: 14, border: '1px solid ' + theme.border,
      }}>
        {/* Big Gini Number */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 12 }}>
          <div>
            <div style={{ fontSize: 10, color: theme.textMuted, textTransform: 'uppercase', letterSpacing: 1, marginBottom: 2 }}>
              Gini Impurity
            </div>
            <div style={{
              fontSize: 36, fontWeight: 700, color: giniColor,
              transition: 'color 0.3s ease', lineHeight: 1,
            }}>
              {gini.toFixed(4)}
            </div>
          </div>
          <div style={{ flex: 1 }}>
            {/* Gauge bar */}
            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 9, color: theme.textMuted, marginBottom: 3 }}>
              <span>0 (pure)</span>
              <span>0.75 (max)</span>
            </div>
            <div style={{
              height: 12, background: theme.surfaceAlt, borderRadius: 6,
              overflow: 'hidden', position: 'relative',
            }}>
              <div style={{
                height: '100%', borderRadius: 6,
                width: giniPct + '%',
                background: 'linear-gradient(90deg, ' + theme.textMuted + ', ' + giniColor + ')',
                transition: 'width 0.4s ease, background 0.4s ease',
              }} />
            </div>
          </div>
        </div>

        {/* Color Proportions */}
        <div style={{ marginBottom: 14 }}>
          <div style={{ fontSize: 10, color: theme.textMuted, marginBottom: 6 }}>Color Distribution</div>
          <div style={{
            display: 'flex', height: 20, borderRadius: 6, overflow: 'hidden',
            background: theme.surfaceAlt,
          }}>
            {terms.map((t, i) => (
              t.count > 0 ? (
                <div key={i} style={{
                  width: (t.p * 100) + '%',
                  background: COLORS[i],
                  opacity: 0.8,
                  transition: 'width 0.4s ease',
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontSize: 9, fontWeight: 700, color: '#000',
                  overflow: 'hidden',
                }}>
                  {t.count > 1 ? (t.p * 100).toFixed(0) + '%' : ''}
                </div>
              ) : null
            ))}
          </div>
          <div style={{ display: 'flex', gap: 10, marginTop: 6, flexWrap: 'wrap' }}>
            {activeTerms.map(t => (
              <div key={t.color} style={{ display: 'flex', alignItems: 'center', gap: 4, fontSize: 10, color: theme.textSecondary }}>
                <div style={{ width: 8, height: 8, borderRadius: 2, background: COLORS[t.color] }} />
                <span>{COLOR_NAMES[t.color]}: {t.count}/8 (p={t.p.toFixed(2)})</span>
              </div>
            ))}
          </div>
        </div>

        {/* Formula */}
        <div style={{
          background: theme.surfaceAlt, borderRadius: 8, padding: 12,
          fontSize: 11, lineHeight: 1.8,
        }}>
          <div style={{ color: theme.textMuted, fontSize: 10, marginBottom: 4 }}>
            Calculation
          </div>
          <div style={{ color: theme.textSecondary }}>
            <span style={{ color: theme.textMuted }}>G = 1 - </span>
            {'['}
            {activeTerms.map((t, i) => (
              <span key={t.color}>
                {i > 0 ? ' + ' : ''}
                <span style={{ color: COLORS[t.color] }}>({t.p.toFixed(2)})</span>
                <span style={{ color: theme.textMuted, fontSize: 9, verticalAlign: 'super' }}>2</span>
              </span>
            ))}
            {']'}
          </div>
          <div style={{ color: theme.textSecondary }}>
            <span style={{ color: theme.textMuted }}>{'  = 1 - '}</span>
            {'['}
            {activeTerms.map((t, i) => (
              <span key={t.color}>
                {i > 0 ? ' + ' : ''}
                <span style={{ color: COLORS[t.color] }}>{t.pSq.toFixed(4)}</span>
              </span>
            ))}
            {']'}
          </div>
          <div>
            <span style={{ color: theme.textMuted }}>{'  = 1 - '}</span>
            <span style={{ color: theme.textSecondary }}>{sumPSq.toFixed(4)}</span>
            <span style={{ color: theme.textMuted }}>{' = '}</span>
            <span style={{ color: theme.text, fontWeight: 700, fontSize: 13 }}>{gini.toFixed(4)}</span>
          </div>
        </div>
      </div>

      {/* Dynamic Insight */}
      <div style={{
        background: theme.surfaceAlt, borderRadius: 8, padding: '10px 14px',
        fontSize: 12, color: theme.textSecondary, lineHeight: 1.5,
        borderLeft: '3px solid ' + theme.primary,
      }}>
        <span style={{ color: theme.primary, fontWeight: 600 }}>Insight: </span>
        {getInsight()}
      </div>
    </div>
  );
}
